    public void waitForNetworkStateUpdate(long j) {
        int callingUid = Binder.getCallingUid();
        if (ActivityManagerDebugConfig.DEBUG_NETWORK) {
            Slog.d(TAG_NETWORK, "Called from " + callingUid + " to wait for seq: " + j);
        }
        synchronized (this) {
            try {
                boostPriorityForLockedSection();
                UidRecord uidRecord = this.mActiveUids.get(callingUid);
                if (uidRecord == null) {
                    resetPriorityAfterLockedSection();
                    return;
                }
                resetPriorityAfterLockedSection();
                synchronized (uidRecord.networkStateLock) {
                    if (uidRecord.lastDispatchedProcStateSeq < j) {
                        if (ActivityManagerDebugConfig.DEBUG_NETWORK) {
                            Slog.d(TAG_NETWORK, "Uid state change for seq no. " + j + " is not dispatched to NPMS yet, so don't wait. Uid: " + callingUid + " lastProcStateSeqDispatchedToObservers: " + uidRecord.lastDispatchedProcStateSeq);
                        }
                        return;
                    }
                    if (uidRecord.curProcStateSeq > j) {
                        if (ActivityManagerDebugConfig.DEBUG_NETWORK) {
                            Slog.d(TAG_NETWORK, "Ignore the wait requests for older seq numbers. Uid: " + callingUid + ", curProcStateSeq: " + uidRecord.curProcStateSeq + ", procStateSeq: " + j);
                        }
                        return;
                    }
                    if (uidRecord.lastNetworkUpdatedProcStateSeq >= j) {
                        if (ActivityManagerDebugConfig.DEBUG_NETWORK) {
                            Slog.d(TAG_NETWORK, "Network rules have been already updated for seq no. " + j + ", so no need to wait. Uid: " + callingUid + ", lastProcStateSeqWithUpdatedNetworkState: " + uidRecord.lastNetworkUpdatedProcStateSeq);
                        }
                        return;
                    }
                    try {
                        if (ActivityManagerDebugConfig.DEBUG_NETWORK) {
                            Slog.d(TAG_NETWORK, "Starting to wait for the network rules update. Uid: " + callingUid + " procStateSeq: " + j);
                        }
                        long jUptimeMillis = SystemClock.uptimeMillis();
                        uidRecord.waitingForNetwork = true;
                        uidRecord.networkStateLock.wait(this.mWaitForNetworkTimeoutMs);
                        uidRecord.waitingForNetwork = false;
                        long jUptimeMillis2 = SystemClock.uptimeMillis() - jUptimeMillis;
                        if (jUptimeMillis2 >= this.mWaitForNetworkTimeoutMs || ActivityManagerDebugConfig.DEBUG_NETWORK) {
                            Slog.w(TAG_NETWORK, "Total time waited for network rules to get updated: " + jUptimeMillis2 + ". Uid: " + callingUid + " procStateSeq: " + j + " UidRec: " + uidRecord + " validateUidRec: " + this.mValidateUids.get(callingUid));
                        }
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                    }
                }
            } catch (Throwable th) {
                resetPriorityAfterLockedSection();
                throw th;
            }
        }
    }

    public void waitForBroadcastIdle(PrintWriter printWriter) {
        boolean z;
        enforceCallingPermission("android.permission.DUMP", "waitForBroadcastIdle()");
        while (true) {
            synchronized (this) {
                try {
                    boostPriorityForLockedSection();
                    z = true;
                    for (BroadcastQueue broadcastQueue : this.mBroadcastQueues) {
                        if (!broadcastQueue.isIdle()) {
                            String str = "Waiting for queue " + broadcastQueue + " to become idle...";
                            printWriter.println(str);
                            printWriter.flush();
                            Slog.v(TAG, str);
                            z = false;
                        }
                    }
                } catch (Throwable th) {
                    resetPriorityAfterLockedSection();
                    throw th;
                }
            }
            resetPriorityAfterLockedSection();
            if (z) {
                printWriter.println("All broadcast queues are idle!");
                printWriter.flush();
                Slog.v(TAG, "All broadcast queues are idle!");
                return;
            }
            SystemClock.sleep(1000L);
        }
    }

